  1→import { lstat, readFile, realpath } from "fs/promises";
  2→import { glob } from "glob";
  3→import { basename, dirname, resolve } from "path";
  4→import { detectCrossReference } from "./file-reference-detector";
  5→
  6→/**
  7→ * Find all Claude Code rules files (.claude/rules/ *.md) recursively.
  8→ * Excludes hidden directories within .claude/rules (e.g., .archived/, .backup/).
  9→ * @param baseDir - The base directory to search in
 10→ * @param maxDepth - Maximum directory depth. undefined = unlimited
 11→ * @param verbose - If true, log debug information
 12→ * @returns Array of absolute paths to rules files
 13→ */
 14→export async function findClaudeRulesFiles(
 15→	baseDir: string = process.cwd(),
 16→	maxDepth?: number,
 17→	verbose?: boolean,
 18→): Promise<string[]> {
 19→	const globOptions = {
 20→		cwd: baseDir,
 21→		absolute: true,
 22→		nocase: true,
 23→		dot: true, // Include .claude directory
 24→		ignore: [
 25→			"**/node_modules/**",
 26→			"**/dist/**",
 27→			"**/build/**",
 28→			"**/.git/**",
 29→			"**/vendor/**",
 30→			"**/coverage/**",
 31→		],
 32→	};
 33→
 34→	// Search for .claude/rules/**/*.md at any depth
 35→	const rulesFiles = await glob("**/.claude/rules/**/*.md", globOptions);
 36→
 37→	// Filter out hidden directories within .claude/rules
 38→	// Pattern: /.claude/rules/.<hidden>/
 39→	const filteredFiles = rulesFiles.filter((file) => {
 40→		// Check if any path segment after ".claude/rules/" starts with a dot
 41→		const rulesIndex = file.indexOf(".claude/rules/");
 42→		if (rulesIndex === -1) return true; // Safety check
 43→
 44→		const afterRulesPath = file.slice(rulesIndex + ".claude/rules/".length);
 45→		const segments = afterRulesPath.split("/");
 46→
 47→		// Check all segments except the last one (the filename)
 48→		for (let i = 0; i < segments.length - 1; i++) {
 49→			if (segments[i]!.startsWith(".")) {
 50→				if (verbose) {
 51→					console.log(
 52→						`[FileFinder] Excluded hidden directory: ${file} (segment: ${segments[i]})`,
 53→					);
 54→				}
 55→				return false;
 56→			}
 57→		}
 58→		return true;
 59→	});
 60→
 61→	// Filter by depth if maxDepth is specified
 62→	let result = filteredFiles;
 63→	if (maxDepth !== undefined) {
 64→		const normalizedBaseDir = resolve(baseDir);
 65→		result = filteredFiles.filter((file) => {
 66→			const relativePath = file.slice(normalizedBaseDir.length + 1);
 67→			const depth = relativePath.split("/").length - 1;
 68→			return depth <= maxDepth;
 69→		});
 70→	}
 71→
 72→	if (verbose && result.length > 0) {
 73→		console.log(
 74→			`[FileFinder] Found ${result.length} Claude Code rules file(s)`,
 75→		);
 76→	}
 77→
 78→	return result;
 79→}
