 81→/**
 82→ * Find all Cursor rules files (.cursor/rules/ *.md and *.mdc) recursively.
 83→ * Excludes hidden directories within .cursor/rules (e.g., .archived/, .backup/).
 84→ * @param baseDir - The base directory to search in
 85→ * @param maxDepth - Maximum directory depth. undefined = unlimited
 86→ * @param verbose - If true, log debug information
 87→ * @returns Array of absolute paths to rules files
 88→ */
 89→export async function findCursorRulesFiles(
 90→	baseDir: string = process.cwd(),
 91→	maxDepth?: number,
 92→	verbose?: boolean,
 93→): Promise<string[]> {
 94→	const globOptions = {
 95→		cwd: baseDir,
 96→		absolute: true,
 97→		nocase: true,
 98→		dot: true,
 99→		ignore: [
100→			"**/node_modules/**",
101→			"**/dist/**",
102→			"**/build/**",
103→			"**/.git/**",
104→			"**/vendor/**",
105→			"**/coverage/**",
106→		],
107→	};
108→
109→	// Search for .cursor/rules/**/*.md and .cursor/rules/**/*.mdc at any depth
110→	const [mdFiles, mdcFiles] = await Promise.all([
111→		glob("**/.cursor/rules/**/*.md", globOptions),
112→		glob("**/.cursor/rules/**/*.mdc", globOptions),
113→	]);
114→
115→	const rulesFiles = [...mdFiles, ...mdcFiles];
116→
117→	// Filter out hidden directories within .cursor/rules
118→	const filteredFiles = rulesFiles.filter((file) => {
119→		const rulesIndex = file.indexOf(".cursor/rules/");
120→		if (rulesIndex === -1) return true;
121→
122→		const afterRulesPath = file.slice(rulesIndex + ".cursor/rules/".length);
123→		const segments = afterRulesPath.split("/");
124→
125→		for (let i = 0; i < segments.length - 1; i++) {
126→			if (segments[i]!.startsWith(".")) {
127→				if (verbose) {
128→					console.log(
129→						`[FileFinder] Excluded hidden directory: ${file} (segment: ${segments[i]})`,
130→					);
131→				}
132→				return false;
133→			}
134→		}
135→		return true;
136→	});
137→
138→	// Filter by depth if maxDepth is specified
139→	let result = filteredFiles;
140→	if (maxDepth !== undefined) {
141→		const normalizedBaseDir = resolve(baseDir);
142→		result = filteredFiles.filter((file) => {
143→			const relativePath = file.slice(normalizedBaseDir.length + 1);
144→			const depth = relativePath.split("/").length - 1;
145→			return depth <= maxDepth;
146→		});
147→	}
148→
149→	if (verbose && result.length > 0) {
150→		console.log(`[FileFinder] Found ${result.length} Cursor rules file(s)`);
151→	}
152→
153→	return result;
154→}
