156→/**
157→ * Find all SKILL.md files across all agent skill directories.
158→ * Searches: .cursor/skills/, .claude/skills/, .agents/skills/, .github/skills/
159→ * @param baseDir - The base directory to search in
160→ * @param maxDepth - Maximum directory depth. undefined = unlimited
161→ * @param verbose - If true, log debug information
162→ * @returns Array of absolute paths to SKILL.md files
163→ */
164→export async function findSkillFiles(
165→	baseDir: string = process.cwd(),
166→	maxDepth?: number,
167→	verbose?: boolean,
168→): Promise<string[]> {
169→	const globOptions = {
170→		cwd: baseDir,
171→		absolute: true,
172→		nocase: true,
173→		dot: true,
174→		ignore: [
175→			"**/node_modules/**",
176→			"**/dist/**",
177→			"**/build/**",
178→			"**/.git/**",
179→			"**/vendor/**",
180→			"**/coverage/**",
181→		],
182→	};
183→
184→	const [cursorSkills, claudeSkills, agentsSkills, githubSkills] =
185→		await Promise.all([
186→			glob("**/.cursor/skills/**/SKILL.md", globOptions),
187→			glob("**/.claude/skills/**/SKILL.md", globOptions),
188→			glob("**/.agents/skills/**/SKILL.md", globOptions),
189→			glob("**/.github/skills/**/SKILL.md", globOptions),
190→		]);
191→
192→	const allSkillFiles = [
193→		...cursorSkills,
194→		...claudeSkills,
195→		...agentsSkills,
196→		...githubSkills,
197→	];
198→
199→	// Filter by depth if maxDepth is specified
200→	let result = allSkillFiles;
201→	if (maxDepth !== undefined) {
202→		const normalizedBaseDir = resolve(baseDir);
203→		result = allSkillFiles.filter((file) => {
204→			const relativePath = file.slice(normalizedBaseDir.length + 1);
205→			const depth = relativePath.split("/").length - 1;
206→			return depth <= maxDepth;
207→		});
208→	}
209→
210→	if (verbose && result.length > 0) {
211→		console.log(`[FileFinder] Found ${result.length} SKILL.md file(s)`);
212→	}
213→
214→	return result;
215→}
