217→/**
218→ * Check if a file is a Cursor rules file.
219→ */
220→function isCursorRulesFile(filePath: string): boolean {
221→	return filePath.includes(".cursor/rules/");
222→}
223→
224→/**
225→ * Resolve symlinks and deduplicate files that point to the same target.
226→ * Handles circular symlinks, broken symlinks, and permission errors gracefully.
227→ * @param files - List of absolute file paths (may include symlinks)
228→ * @param verbose - If true, log symlink relationships and errors
229→ * @returns Deduplicated list of file paths (symlinks resolved to unique targets)
230→ */
231→async function resolveSymlinks(
232→	files: string[],
233→	verbose: boolean = false,
234→): Promise<string[]> {
235→	const canonicalMap = new Map<string, string>(); // canonical path → first discovered file
236→	const result: string[] = [];
237→
238→	for (const file of files) {
239→		try {
240→			const stats = await lstat(file);
241→
242→			if (!stats.isSymbolicLink()) {
243→				// Regular file - track its canonical path for deduplication against symlinks
244→				const canonical = await realpath(file);
245→				if (!canonicalMap.has(canonical)) {
246→					canonicalMap.set(canonical, file);
247→					result.push(file);
248→				} else if (verbose) {
249→					console.log(
250→						`[FileFinder] Deduplicated: ${file} (same target as ${canonicalMap.get(canonical)})`,
251→					);
252→				}
253→				continue;
254→			}
255→
256→			// Symlink detected - resolve to canonical path
257→			try {
258→				const canonical = await realpath(file);
259→
260→				if (canonicalMap.has(canonical)) {
261→					// Duplicate - skip this symlink as we already have a file pointing to this target
262→					if (verbose) {
263→						console.log(
264→							`[FileFinder] Deduplicated symlink: ${file} → ${canonical} (same target as ${canonicalMap.get(canonical)})`,
265→						);
266→					}
267→					continue;
268→				}
269→
270→				// New target - keep this symlink
271→				if (verbose) {
272→					console.log(`[FileFinder] Symlink: ${file} → ${canonical}`);
273→				}
274→				result.push(file);
275→				canonicalMap.set(canonical, file);
276→			} catch (error) {
277→				// Handle symlink-specific errors
278→				const nodeError = error as NodeJS.ErrnoException;
279→				if (nodeError.code === "ELOOP") {
280→					if (verbose) {
281→						console.warn(`[FileFinder] Circular symlink detected: ${file}`);
282→					}
283→				} else if (nodeError.code === "ENOENT") {
284→					if (verbose) {
285→						console.warn(
286→							`[FileFinder] Broken symlink: ${file} (target not found)`,
287→						);
288→					}
289→				} else if (nodeError.code === "EACCES") {
290→					if (verbose) {
291→						console.warn(`[FileFinder] Permission denied for symlink: ${file}`);
292→					}
293→				} else {
294→					if (verbose) {
295→						console.warn(
296→							`[FileFinder] Error resolving symlink ${file}:`,
297→							error,
298→						);
299→					}
300→				}
301→				// Skip problematic symlinks
302→				continue;
303→			}
304→		} catch (error) {
305→			// lstat failed - include file anyway (graceful degradation)
306→			if (verbose) {
307→				console.warn(`[FileFinder] Error checking ${file}:`, error);
308→			}
309→			result.push(file);
310→		}
311→	}
312→
313→	return result;
314→}
315→
316→/**
317→ * Find all AGENTS.md, CLAUDE.md, and Copilot instruction files recursively in a directory.
318→ * These are "context files" - all serve the same purpose of providing AI agent instructions.
319→ * - AGENTS.md and CLAUDE.md: General AI agent instructions
320→ * - copilot-instructions.md: Github Copilot instructions (in .github/ directory)
321→ * - *.instructions.md: Github Copilot instructions (in .github/instructions/ directory)
322→ * Excludes node_modules and other common ignore patterns.
323→ * @param baseDir - The base directory to search in
324→ * @param maxDepth - Maximum directory depth (0 = root only, 1 = root + 1 level, etc.). undefined = unlimited
325→ * @param verbose - If true, log debug information about deduplication
326→ */
327→export async function findAgentsFiles(
328→	baseDir: string = process.cwd(),
329→	maxDepth?: number,
330→	verbose?: boolean,
331→): Promise<string[]> {
332→	const globOptions = {
333→		cwd: baseDir,
334→		absolute: true,
335→		nocase: true, // Match AGENTS.md, agents.md, Agents.md, CLAUDE.md, claude.md, etc.
336→		dot: true, // Include hidden directories (e.g., .claude/, .github/)
337→		ignore: [
338→			"**/node_modules/**",
339→			"**/dist/**",
340→			"**/build/**",
341→			"**/.git/**",
342→			"**/vendor/**",
343→			"**/coverage/**",
344→		],
345→	};
346→
347→	// Search for AGENTS.md, CLAUDE.md, copilot-instructions.md, *.instructions.md, .github/instructions/*.md, .claude/rules/*.md, .cursor/rules/*.md/*.mdc, and SKILL.md patterns
348→	const [
349→		agentsFiles,
350→		claudeFiles,
351→		copilotFiles,
352→		instructionFiles,
353→		instructionMdFiles,
354→		rulesFiles,
355→		cursorRulesFiles,
356→		skillFiles,
357→	] = await Promise.all([
358→		glob("**/AGENTS.md", globOptions),
359→		glob("**/CLAUDE.md", globOptions),
360→		glob("**/.github/**/copilot-instructions.md", globOptions),
361→		glob("**/.github/instructions/**/*.instructions.md", globOptions),
362→		glob("**/.github/instructions/**/*.md", globOptions),
363→		findClaudeRulesFiles(baseDir, maxDepth, verbose),
364→		findCursorRulesFiles(baseDir, maxDepth, verbose),
365→		findSkillFiles(baseDir, maxDepth, verbose),
366→	]);
367→
368→	// Combine results (deduplicate since *.md glob overlaps with *.instructions.md glob)
369→	const allFiles = [
370→		...new Set([
371→			...agentsFiles,
372→			...claudeFiles,
373→			...copilotFiles,
374→			...instructionFiles,
375→			...instructionMdFiles,
376→			...rulesFiles,
377→			...cursorRulesFiles,
378→			...skillFiles,
379→		]),
380→	];
381→
382→	// Filter by depth if maxDepth is specified
383→	let filteredFiles = allFiles;
384→	if (maxDepth !== undefined) {
385→		// Normalize base directory path
386→		const normalizedBaseDir = resolve(baseDir);
387→
388→		filteredFiles = allFiles.filter((file) => {
389→			// Get the relative path from baseDir
390→			const relativePath = file.slice(normalizedBaseDir.length + 1);
391→
392→			// Count directory separators to determine depth
393→			// depth 0 = file at root (AGENTS.md)
394→			// depth 1 = file one level down (subdir/AGENTS.md)
395→			const depth = relativePath.split("/").length - 1;
396→
397→			return depth <= maxDepth;
398→		});
399→	}
400→
401→	// Resolve symlinks and deduplicate files that point to the same target
402→	const symlinkResolvedFiles = await resolveSymlinks(filteredFiles, verbose);
403→
404→	// Deduplicate files in the same directory with identical content (AGENTS.md vs CLAUDE.md)
405→	const deduplicatedFiles = await deduplicateContextFiles(
406→		symlinkResolvedFiles,
407→		verbose,
408→	);
409→
410→	// Global deduplication for copilot-instructions.md files
411→	// If a copilot-instructions.md has identical content to any AGENTS.md or CLAUDE.md, exclude it
412→	const copilotDeduplicatedFiles = await deduplicateCopilotInstructions(
413→		deduplicatedFiles,
414→		verbose,
415→	);
416→
417→	// Global deduplication for .cursor/rules/ files
418→	// If a cursor rule has identical content to any AGENTS.md or CLAUDE.md, exclude it
419→	const globallyDeduplicatedFiles = await deduplicateCursorRules(
420→		copilotDeduplicatedFiles,
421→		verbose,
422→	);
423→
424→	// Sort by path depth (shallower files first)
425→	return globallyDeduplicatedFiles.sort((a, b) => {
426→		const depthA = a.split("/").length;
427→		const depthB = b.split("/").length;
428→		return depthA - depthB;
429→	});
430→}
431→
432→/**
433→ * Deduplicate context files (AGENTS.md and CLAUDE.md) in the same directory.
434→ * If both files exist in the same directory with identical content (after trimming whitespace),
435→ * keep only AGENTS.md to avoid redundant evaluation.
436→ * @param files - List of absolute file paths
437→ * @param verbose - If true, log debug information about deduplication
438→ * @returns Deduplicated list of file paths
439→ */
440→async function deduplicateContextFiles(
441→	files: string[],
442→	verbose?: boolean,
443→): Promise<string[]> {
444→	// Group files by directory
445→	const filesByDir = new Map<string, string[]>();
446→	for (const file of files) {
447→		const dir = dirname(file);
448→		if (!filesByDir.has(dir)) {
449→			filesByDir.set(dir, []);
450→		}
451→		filesByDir.get(dir)!.push(file);
452→	}
453→
454→	const result: string[] = [];
455→
456→	for (const [dir, filesInDir] of filesByDir) {
457→		// If only one file in directory, keep it
458→		if (filesInDir.length === 1) {
459→			result.push(filesInDir[0]!);
460→			continue;
461→		}
462→
463→		// Find AGENTS.md and CLAUDE.md files (case-insensitive)
464→		const agentsFile = filesInDir.find(
465→			(f) => basename(f).toLowerCase() === "agents.md",
466→		);
467→		const claudeFile = filesInDir.find(
468→			(f) => basename(f).toLowerCase() === "claude.md",
469→		);
470→
471→		// If both exist in same directory, compare contents
472→		if (agentsFile && claudeFile) {
473→			try {
474→				const [agentsContent, claudeContent] = await Promise.all([
475→					readFile(agentsFile, "utf-8"),
476→					readFile(claudeFile, "utf-8"),
477→				]);
478→
479→				// Exact match after trimming whitespace
480→				if (agentsContent.trim() === claudeContent.trim()) {
481→					// Keep only AGENTS.md (preferred)
482→					if (verbose) {
483→						console.log(
484→							`[FileFinder] Deduplicated: ${claudeFile} (identical to ${agentsFile})`,
485→						);
486→					}
487→					result.push(agentsFile);
488→				} else {
489→					// Different content - check for @ file reference annotations
490→					const crossRef = detectCrossReference(agentsContent, claudeContent);
491→					if (crossRef.hasReference) {
492→						// One file is just a pointer, keep only the content file
493→						const contentFile =
494→							crossRef.contentFile === "agents" ? agentsFile : claudeFile;
495→						const pointerFile =
496→							crossRef.referenceFile === "agents" ? agentsFile : claudeFile;
497→						if (verbose) {
498→							console.log(
499→								`[FileFinder] Deduplicated: ${pointerFile} (file reference to ${contentFile})`,
500→							);
501→						}
502→						result.push(contentFile);
503→					} else {
504→						// Different content, keep both
505→						if (verbose) {
506→							console.log(
507→								`[FileFinder] Keeping both files in ${dir} (different content)`,
508→							);
509→						}
510→						result.push(agentsFile, claudeFile);
511→					}
512→				}
513→			} catch (error) {
514→				// If we can't read files, keep both to be safe
515→				if (verbose) {
516→					console.log(
517→						`[FileFinder] Error reading files in ${dir}, keeping both:`,
518→						error,
519→					);
520→				}
521→				result.push(agentsFile, claudeFile);
522→			}
523→		} else {
524→			// Only one type exists, add all files
525→			result.push(...filesInDir);
526→		}
527→	}
528→
529→	return result;
530→}
531→
532→/**
533→ * Check if a file is a Copilot instructions file (case-insensitive).
534→ * Matches both patterns:
535→ * - copilot-instructions.md (in .github/ directory)
536→ * - *.instructions.md (in .github/instructions/ directory)
537→ */
538→function isCopilotInstructionsFile(filePath: string): boolean {
539→	const filename = basename(filePath).toLowerCase();
540→
541→	// Original pattern: copilot-instructions.md
542→	if (filename === "copilot-instructions.md") {
543→		return true;
544→	}
545→
546→	// New pattern: *.instructions.md in .github/instructions/ directory
547→	if (
548→		filename.endsWith(".instructions.md") &&
549→		filePath.includes(".github/instructions/")
550→	) {
551→		return true;
552→	}
553→
554→	// Backward compat: plain .md files in .github/instructions/ directory
555→	if (filename.endsWith(".md") && filePath.includes(".github/instructions/")) {
556→		return true;
557→	}
558→
559→	return false;
560→}
561→
562→/**
563→ * Global deduplication for copilot-instructions.md files.
564→ * If a copilot-instructions.md has identical content to ANY AGENTS.md or CLAUDE.md
565→ * in the repository (not just same directory), exclude it.
566→ * @param files - List of absolute file paths (already deduplicated within directories)
567→ * @param verbose - If true, log debug information about deduplication
568→ * @returns Deduplicated list of file paths
569→ */
570→async function deduplicateCopilotInstructions(
571→	files: string[],
572→	verbose?: boolean,
573→): Promise<string[]> {
574→	// Separate copilot-instructions.md files from others
575→	const copilotFiles = files.filter(isCopilotInstructionsFile);
576→	const otherFiles = files.filter((f) => !isCopilotInstructionsFile(f));
577→
578→	// If no copilot files, nothing to deduplicate
579→	if (copilotFiles.length === 0) {
580→		return files;
581→	}
582→
583→	// Read content of all AGENTS.md and CLAUDE.md files
584→	const otherContents = new Map<string, string>();
585→	await Promise.all(
586→		otherFiles.map(async (file) => {
587→			try {
588→				const content = await readFile(file, "utf-8");
589→				otherContents.set(file, content.trim());
590→			} catch {
591→				// Ignore read errors
592→			}
593→		}),
594→	);
595→
596→	// Filter copilot files, excluding those with identical content to any other file
597→	const uniqueCopilotFiles: string[] = [];
598→	for (const copilotFile of copilotFiles) {
599→		try {
600→			const copilotContent = (await readFile(copilotFile, "utf-8")).trim();
601→
602→			// Check if content matches any AGENTS.md or CLAUDE.md
603→			let isDuplicate = false;
604→			for (const [otherFile, otherContent] of otherContents) {
605→				if (copilotContent === otherContent) {
606→					if (verbose) {
607→						console.log(
608→							`[FileFinder] Deduplicated: ${copilotFile} (identical content to ${otherFile})`,
609→						);
610→					}
611→					isDuplicate = true;
612→					break;
613→				}
614→			}
615→
616→			if (!isDuplicate) {
617→				uniqueCopilotFiles.push(copilotFile);
618→			}
619→		} catch {
620→			// If we can't read the copilot file, keep it to be safe
621→			uniqueCopilotFiles.push(copilotFile);
622→		}
623→	}
624→
625→	return [...otherFiles, ...uniqueCopilotFiles];
626→}
627→
628→/**
629→ * Global deduplication for Cursor rules files.
630→ * If a .cursor/rules/ file has identical content to ANY AGENTS.md or CLAUDE.md
