// Combine results (deduplicate since *.md glob overlaps with *.instructions.md glob)
// Exclude skill-directory files: SKILL.md files AND any AGENTS.md/CLAUDE.md colocated
// inside skill directories. Skills metadata is already included in prompts via
// buildSkillsSection() (frontmatter name + description), so full content is not needed.
const skillDirPatterns = [
	"/.cursor/skills/",
	"/.claude/skills/",
	"/.agents/skills/",
	"/.github/skills/",
];
const isInSkillDirectory = (filePath: string) =>
	skillDirPatterns.some((pattern) => filePath.includes(pattern));

const allFiles = [
	...new Set([
